import gurobipy as gp
from gurobipy import GRB

# Define the routes and their sequences
routes = {
    'R1': [('C6', 10), ('C3', 4), ('C1', 7), ('C4', 1), ('C9', 10), ('C7', 4), ('C5', 7), ('C2', 10), ('C8', 8)],
    'R2': [('C8', 2), ('C7', 9), ('C4', 10), ('C9', 8), ('C1', 3), ('C3', 10), ('C5', 7), ('C6', 4), ('C2', 3)],
    'R3': [('C5', 10), ('C1', 1), ('C4', 8), ('C3', 3), ('C7', 5), ('C6', 4), ('C9', 6), ('C8', 1), ('C2', 5)],
    'R4': [('C7', 3), ('C4', 7), ('C1', 10), ('C2', 8), ('C5', 6), ('C8', 8), ('C9', 10), ('C6', 3), ('C3', 1)],
    'R5': [('C7', 10), ('C9', 4), ('C3', 8), ('C8', 4), ('C2', 3), ('C6', 8), ('C5', 8), ('C4', 1), ('C1', 7)],
    'R6': [('C4', 4), ('C5', 5), ('C6', 3), ('C9', 3), ('C1', 6), ('C3', 4), ('C2', 10), ('C8', 10), ('C7', 3)],
    'R7': [('C1', 5), ('C2', 10), ('C8', 6), ('C3', 2), ('C5', 7), ('C6', 5), ('C7', 6), ('C9', 10), ('C4', 9)],
    'R8': [('C9', 10), ('C5', 8), ('C7', 6), ('C1', 10), ('C8', 4), ('C6', 2), ('C4', 7), ('C2', 7), ('C3', 2)],
    'R9': [('C5', 1), ('C6', 6), ('C8', 6), ('C2', 9), ('C1', 10), ('C9', 10), ('C4', 7), ('C7', 9), ('C3', 2)]
}

# Create model
model = gp.Model("DeliveryRouteScheduling")

# Big-M value (sum of all durations)
M = sum(d for r in routes.values() for (_, d) in r)

# Decision variables
start = {}
end = {}
for r in routes:
    for s in range(len(routes[r])):
        start[(r, s)] = model.addVar(vtype=GRB.CONTINUOUS, name=f"start_{r}_{s}")
        end[(r, s)] = model.addVar(vtype=GRB.CONTINUOUS, name=f"end_{r}_{s}")

# Binary variables for sequencing
y = {}
for r1 in routes:
    for s1 in range(len(routes[r1])):
        c1 = routes[r1][s1][0]
        for r2 in routes:
            for s2 in range(len(routes[r2])):
                c2 = routes[r2][s2][0]
                if (r1, s1) < (r2, s2) and c1 == c2:
                    y[(r1, s1, r2, s2)] = model.addVar(vtype=GRB.BINARY, name=f"y_{r1}_{s1}_{r2}_{s2}")

# Makespan variable
makespan = model.addVar(vtype=GRB.CONTINUOUS, name="makespan")

# Objective: minimize makespan
model.setObjective(makespan, GRB.MINIMIZE)

# Constraints
# 1. Sequence constraints within each route
for r in routes:
    for s in range(len(routes[r]) - 1):
        model.addConstr(start[(r, s+1)] >= end[(r, s)], f"sequence_{r}_{s}")

# 2. Resource constraints (no overlapping at the same center)
for r1 in routes:
    for s1 in range(len(routes[r1])):
        c1 = routes[r1][s1][0]
        for r2 in routes:
            for s2 in range(len(routes[r2])):
                c2 = routes[r2][s2][0]
                if (r1, s1) < (r2, s2) and c1 == c2:
                    model.addConstr(
                        start[(r2, s2)] >= end[(r1, s1)] - M * (1 - y[(r1, s1, r2, s2)]),
                        f"resource_{r1}_{s1}_{r2}_{s2}_1"
                    )
                    model.addConstr(
                        start[(r1, s1)] >= end[(r2, s2)] - M * y[(r1, s1, r2, s2)],
                        f"resource_{r1}_{s1}_{r2}_{s2}_2"
                    )

# 3. End time definition
for r in routes:
    for s in range(len(routes[r])):
        model.addConstr(
            end[(r, s)] == start[(r, s)] + routes[r][s][1],
            f"end_{r}_{s}"
        )

# 4. Makespan definition
for r in routes:
    for s in range(len(routes[r])):
        model.addConstr(
            makespan >= end[(r, s)],
            f"makespan_{r}_{s}"
        )

# Optimize the model
model.optimize()

# Print the solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal makespan: {makespan.X}")
    print("Schedule:")
    for r in routes:
        for s in range(len(routes[r])):
            c, d = routes[r][s]
            print(f"Route {r}, Step {s+1} at {c}: Start at {start[(r, s)].X}, End at {end[(r, s)].X}")
else:
    print("No optimal solution found.")

# Print objective value for evaluation
if model.status == GRB.OPTIMAL:
    print(f"OBJECTIVE_VALUE: {makespan.X}")

