}

# Create symmetric travel times (add reverse arcs)
for i in facilities:
    for j in facilities:
        if j in travel_times[i]:
            if i not in travel_times[j]:
                travel_times[j][i] = travel_times[i][j]

# Create model
model = gp.Model("TSP_Logistics")

# Decision variables
x = model.addVars(facilities, facilities, vtype=GRB.BINARY, name="x")
u = model.addVars(facilities, vtype=GRB.CONTINUOUS, name="u")

# Objective: minimize total travel time
model.setObjective(gp.quicksum(travel_times[i][j] * x[i,j] for i in facilities for j in facilities if i != j and j in travel_times[i]), GRB.MINIMIZE)

# Constraints
# 1. Flow conservation
for i in facilities:
    model.addConstr(gp.quicksum(x[i,j] for j in facilities if i != j and j in travel_times[i]) == 1, name=f"out_{i}")
    model.addConstr(gp.quicksum(x[j,i] for j in facilities if i != j and i in travel_times[j]) == 1, name=f"in_{i}")

# 2. No direct travel between Alpha and Beta
model.addConstr(x['Alpha', 'Beta'] == 0, name="no_Alpha_Beta")
model.addConstr(x['Beta', 'Alpha'] == 0, name="no_Beta_Alpha")

# 3. Critical segment constraint
model.addConstr(x['Beta', 'Gamma'] + x['Gamma', 'Delta'] == 1, name="critical_segment")

# 4. Subtour elimination (MTZ)
n = len(facilities)
for i in facilities:
    for j in facilities:
        if i != j and j in travel_times[i] and i != 'Alpha' and j != 'Alpha':
            model.addConstr(u[i] - u[j] + n * x[i,j] <= n - 1, name=f"subtour_{i}_{j}")

# Solve the model
model.optimize()

# Print solution
if model.status == GRB.OPTIMAL:
    print(f"Optimal total travel time: {model.objVal:.1f} minutes")
    print("\nTour:")
    current = 'Alpha'
    tour = [current]
    visited = set([current])
    while len(visited) < n:
        for j in facilities:
            if j != current and j in travel_times[current] and x[current,j].X > 0.5:
                tour.append(j)
                visited.add(j)
                current = j
                break
    tour.append('Alpha')  # Return to origin
    print(" -> ".join(tour))
else:
    print("No optimal solution found.")
